const Mustache = require('mustache');
return items.map(item => {
  const r = item.json;
  const view = { customer: r.customer, invoice_id: r.invoice_id, amount_remaining: Number(r.amount_remaining).toFixed(2), due_date: r.due_date };
  const text = Mustache.render(r.body, view);
  return { json: { to: r.customer_email, subject: Mustache.render(r.title, view), text } };
});
